      playerSegmentation: { supported: true, description: 'Satori Audiences enable dynamic player segmentation based on default properties (demographics, device) and computed properties from in-game events with regex matching.', sourceUrl: 'https://heroiclabs.com/docs/satori/concepts/audiences/' },
