      revenueAnalytics: { supported: true, description: 'Satori Dashboard provides ARPDAU (Average Revenue Per Daily Active User) and Daily Revenue graphs. Revenue metric type tracks USD cents with Databricks integration for advanced analysis.', sourceUrl: 'https://heroiclabs.com/satori/analytics/' },
      customDashboards: { supported: true, description: 'Satori Reports provide retention reports (D1-D30), session metrics, and engagement tracking. Supports filtering by date, country, version, platform, and experiment/event participation.', sourceUrl: 'https://heroiclabs.com/docs/satori/concepts/reports/' },
      multiplayer: { supported: true, description: 'Nakama provides client-relayed, server-authoritative, active turn-based, and passive turn-based multiplayer. A single node handles hundreds or thousands of concurrent matches.', sourceUrl: 'https://heroiclabs.com/docs/nakama/concepts/multiplayer/' },
