      chat: { supported: true, description: 'Nakama real-time chat supports public rooms (millions scale), group chat (member-restricted), and direct messaging. Features message persistence, hidden presence, and multi-device connectivity.', sourceUrl: 'https://heroiclabs.com/docs/nakama/concepts/chat/' },
      cloudSave: { supported: true, description: 'Nakama Storage Engine provides cloud save with collections, object ownership, granular access permissions, JSONB queries, and batch operations. PostgreSQL-compatible storage.', sourceUrl: 'https://heroiclabs.com/docs/nakama/concepts/storage/' },
      serverlessLogic: { supported: true, description: 'Nakama Server Framework provides serverless-style execution through TypeScript/JavaScript VM, Go plugins, and Lua modules. RPCs exposed via REST, WebSocket, and gRPC without rebuilding.', sourceUrl: 'https://heroiclabs.com/docs/nakama/server-framework/introduction/' },
