      selfHosting: { supported: true, description: 'Nakama is Apache 2.0 licensed enabling free self-hosting on any cloud or private infrastructure. Docker Compose for quick setup. All client SDKs also Apache 2.0.', sourceUrl: 'https://github.com/heroiclabs/nakama' },
      multiplatformSDK: { supported: true, description: 'Nakama SDKs for Unity/.NET, Unreal, C++, Godot 3/4, JavaScript, Swift, Java/Android, Dart/Flutter, Defold, and Cocos2d. Console SDKs available on request.', sourceUrl: 'https://heroiclabs.com/docs/nakama/client-libraries/' },
