      iapValidation: { supported: true, description: 'Unity IAP provides receipt validation for local (StoreKit 2 for iOS) and remote (server-side) verification. Pairing IAP with Economy enables secure validation against fraud.', sourceUrl: 'https://docs.unity.com/ugs/en-us/manual/iap/manual/receipt-validation' },
