      chat: { supported: true, description: 'Chat functionality via room messaging system using send() and broadcast() methods. RelayRoom provides foundation for chat-style communication between clients.', sourceUrl: 'https://docs.colyseus.io/room/built-in/relay' },
      cloudSave: false,
      serverlessLogic: false,
      dedicatedServers: { supported: true, description: 'Self-hosted dedicated infrastructure using Docker, PM2, or Nginx. Vultr offers pre-configured Colyseus marketplace image with Node.js and PM2.', sourceUrl: 'https://docs.colyseus.io/deployment' },
      globalScaling: { supported: true, description: 'Horizontal scaling via RedisPresence and RedisDriver for inter-process communication. Colyseus Cloud offers 32 global deployment locations with automatic region configuration.', sourceUrl: 'https://docs.colyseus.io/deployment/scalability' },
      adminDashboard: { supported: true, description: '@colyseus/monitor web-based admin dashboard for listing rooms, viewing room states, sending/broadcasting messages, disconnecting clients, and disposing rooms. HTTP basic auth supported.', sourceUrl: 'https://docs.colyseus.io/tools/monitoring' },
      playerSupport: false,
