      managedServices: { supported: true, description: 'Colyseus Cloud official managed hosting from $15/month. 32 global locations, automatic SSL, DDoS protection (Layer 3/4), rolling updates, graceful shutdown, no CCU/DAU/MAU limits.', sourceUrl: 'https://colyseus.io/cloud-managed-hosting/' },
      selfHosting: { supported: true, description: 'Fully self-hostable under MIT license. Deploy using Docker, PM2, or traditional Node.js hosting with Nginx/Apache reverse proxies. Cloud-agnostic deployment.', sourceUrl: 'https://docs.colyseus.io/deployment' },
      multiplatformSDK: { supported: true, description: 'Official SDKs for TypeScript/JavaScript, React, Unity (C#), Defold (Lua), Construct 3, Cocos Creator, Haxe (OpenFL, HaxeFlixel, Heaps), Discord Activity, and WeChat.', sourceUrl: 'https://docs.colyseus.io/getting-started' },
      serverAuthoritative: { supported: true, description: 'Server-authoritative architecture where only the server mutates game state. Clients send messages requesting changes; server validates actions before updating and syncing state.', sourceUrl: 'https://docs.colyseus.io/state' },
