      customizable: { supported: true, description: 'Highly customizable through room class inheritance, custom schema definitions, configurable transports (WebSocket, uWebSockets.js, WebTransport), custom HTTP routes via Express.', sourceUrl: 'https://docs.colyseus.io/server' },
      extensible: { supported: true, description: 'Designed for extensibility with lifecycle hooks (onCreate, onJoin, onLeave, onDispose, onAuth, onBeforePatch, onBeforeShutdown), custom room implementations, and extendable built-in rooms.', sourceUrl: 'https://docs.colyseus.io/server' },
      inGameMessaging: { supported: true, description: 'Real-time messaging through room system using send() for direct messages and broadcast() for room-wide messages. RelayRoom facilitates message passing between connected clients.', sourceUrl: 'https://docs.colyseus.io/client' },
