      loadTesting: { supported: true, description: '@colyseus/loadtest for stress testing servers. Bot scripts simulate multiple client connections exercising room lifecycle events to identify performance bottlenecks before production.', sourceUrl: 'https://docs.colyseus.io/tools/loadtest' },
